var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"자, 약속한 대로 약을 가져왔다.","JPN":"さあ、約束どおり薬を持ってきた。","ENG":"Hey, I brought the drug as promised.","TWN":"拿去，這是說好的藥。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"양은 부하들이 쓸 만큼 충분해. 블랙 네트워크에서 구하는 것보단 품질이 좋을 거야.","JPN":"部下が全員使うのに十分な量だ。ブラックネットワークで手に入れるよりはいい品だろう。","ENG":"There’s enough for the men. It’s better stuff than what you’d find on the Dark Network.","TWN":"這些量夠你的手下們用，而且品質比黑色網路上賣的還好。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"헤헤……. 대금은 안 받아도 되는 거야?","JPN":"へへ……金はとらないのか？","ENG":"Heh... You don’t need me to pay you?","TWN":"嘿嘿……真的不用付錢嗎？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"필요없어. 우리는 지금 거래가 아니라 협조를 하고 있으니까.","JPN":"必要ない。私たちは今、取引ではなく協力しているだけだから。","ENG":"No. We're not trading now, but cooperating.","TWN":"不用，因為我們現在不是交易關係，而是合作關係。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"용병 신분으로 여기 와 있다는 사실을 잊진 않았겠지?","JPN":"傭兵の身でここに来てるってこと、忘れてはいないだろうな？","ENG":"You didn’t forget that you came here as a mercenary, did you?","TWN":"你沒忘記，你是以傭兵的身分來到這裡的吧？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"결행 전까지, 괜한 트러블은 일으키지 마.","JPN":"決行まで変なトラブルを起こすな。","ENG":"Don’t cause any unnecessary trouble until it’s all over.","TWN":"在行動前不要惹事生非。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"물론이지, 나리. 쥐 죽은 듯이 조용히 지낼 거야.","JPN":"もちろんさ、旦那。じっと過ごすよ。","ENG":"Sure thing, miss. I’ll be as quiet as a mouse.","TWN":"那是當然的，姊。我會像死老鼠般安靜。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"아, 그렇지. 참. 고마워, 나리.","JPN":"ああ、そうだ。ありがとな、旦那。","ENG":"Ah, right. Well. Thank you, miss.","TWN":"對了，姊，真的很謝謝你。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"고맙다니?","JPN":"ありがとうって？","ENG":"What do you mean thank you?","TWN":"謝謝我？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"나리가 아니었으면, 나 같은 건 이런 짓 엄두도 못 냈을 거야.","JPN":"旦那がいなけりゃ、俺なんかにこんなこと、とてもできなかった。","ENG":"If it wasn’t for you, I wouldn’t have been able to do this.","TWN":"要不是姊，像我這種貨色，根本想都不敢想會有這一天。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"나는 원래 부하들을 잔뜩 거느릴 만큼 대단한 사람도 아니고…….","JPN":"俺は元々こんな多くの手下を率るくらいすごい奴でもないし……","ENG":"I’m not really a good enough leader to have this many men under me...","TWN":"我本來就不太會帶領人……"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"아버지가 돌아가신 날 나리가 나타나지 않았다면 분명 아무것도 못하다 정부군 놈들에게 죽었을 거야.","JPN":"おやじが亡くなった日、旦那が現れなかったらきっと何もできずに政府軍の野郎どもにやられてた。","ENG":"If you didn’t show up the day my father died, the government soldiers would have killed me.","TWN":"我爸死掉的那一天，若不是姊的出現，我應該毫無招架之力，只能死在政府軍的手裡。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"……저 자, 정신이 불안정해 보이는군.","JPN":"……あの者、精神が不安定であるな。","ENG":"....That guy. Looks like he is a little unstable.","TWN":"……那個人，精神狀況看起來不太穩定。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"소녀여. 그대가 저 자에게 건넨 약은 인간의 이성을 흐리는 작용을 하고 있다.","JPN":"少女よ。そなたがあの者に渡した薬は人間の理性を濁らせる作用をしている。","ENG":"Girl, the drug that you provided clouds a human’s ability to reason.","TWN":"少女，你給他的藥會使人的精神產生混亂。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"저들이 원하던 거야. 나는 그걸 들어 줬을 뿐이고.","JPN":"彼らが望んだんだ。私はそれを叶えてやっただけ。","ENG":"It’s what they wanted. I just gave them what they want.","TWN":"這就是他們所希望的，而我只是照他們所希望的去做。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"알고 있어? 저들에게 이 도시는 적진 한복판이야.","JPN":"知ってるか？　彼らにとってこの街は敵陣のど真ん中だ。","ENG":"Don’t you know? To them, this city is right in the middle of enemy territory.","TWN":"你知道嗎？對他們而言，這座城市就等於是敵營的中心。"},"stage":{"bg":"HARMONY_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"그리고 얼마 안 있으면 여기서 사람을 죽여야 하지. 조용히 끝날 가능성은 낮아.","JPN":"そして間もなくここで人を殺さなければならない。静かに終わる可能性は低い。","ENG":"And soon we’re going to have to kill someone here. It’s unlikely things are going to end peacefully.","TWN":"而不久後，他們就要在這裡大開殺戒，肯定是一場腥風血雨。"},"stage":{"bg":"HARMONY_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"숨만 쉬어도 스트레스가 치솟는 환경이야.","JPN":"息してるだけでストレスが爆発しそうな環境だ。","ENG":"It’s an extremely stressful situation for them.","TWN":"在這種環境下，連呼吸都會覺得倍感壓力。"},"stage":{"bg":"HARMONY_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"HARMONY_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"인간은 너희 그림자들과 달라. 싸우는 걸 두려워하지. 그래서 다들 그럴싸한 이유를 붙여.","JPN":"人間はあなたたちシャドウとは違う。戦うことを恐れる。それでみんなそれっぽい理由をつけるんだ。","ENG":"Humans are not like Shadows like you. They are afraid to fight. So you need to give them a good reason.","TWN":"人類和你們暗影不一樣，人類害怕戰爭，所以必須賦予戰爭意義。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"가족을 위해, 나라를 위해, 신념을 위해, 신앙을 위해.","JPN":"家族のため、国のため、信念のため、信仰のため。","ENG":"For family, for country, for faith, for honor.","TWN":"像是為家人而戰，為國家而戰，為信念而戰，為信仰而戰。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"나는 그것만으로 부족한 부분을 채워 준 셈이지. 작은 성의를 베푼 게 잘못인가?","JPN":"私がそれだけでは足りない部分を埋めてやったというわけ。小さい誠意を見せたのが間違いなのか？","ENG":"I guess I just filled the remaining gaps for them. Am I wrong to show them such kindness?","TWN":"而我只是強化那個意義，這樣貼心的舉動，有錯嗎？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"궤변이군.","JPN":"詭弁であるな。","ENG":"A fallacious argument.","TWN":"強詞奪理。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"하지만 저 자들이 납득했다면 내가 관여할 권리도 없다.","JPN":"しかしあの者たちが納得したのなら、我が関わる権利もあるまい。","ENG":"Even so, if that is their decision, then I have no right to be involved.","TWN":"不過只要他們可以接受，也不容我置喙。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"내 목적은 오직 마에스트로뿐. 이 도시에 숨어 있다는 첩보가 사실이길 바라마.","JPN":"我の目的はただ一つ、マエストロのみ。この街に潜んでいるという諜報が事実であることを祈ろう。","ENG":"My only purpose is Maestra. I hope that the information of her hiding in this city is true.","TWN":"我的目標只有指揮家，希望說她躲在這座城市裡的情報是真的。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"침식파……. 아니지, 네가 말하는 <color=#ffd34c>역병</color>의 악취로 구분할 수 없나?","JPN":"侵食波……いや、あなたの言う<color=#ffd34c>疫病</color>の悪臭で見分けられないのか？","ENG":"Corruption Rays… I mean, the stench of the <color=#ffd34c>plague</color> you are mentioning can tell the truth?","TWN":"侵蝕波……不對，不能用你說的<color=#ffd34c>瘟疫</color>的惡臭來分辨嗎？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"이 땅은 이미 역병에 물들었다.","JPN":"この地はすでに疫病に染まっている。","ENG":"This land has already been infested with the plague.","TWN":"這塊土地早就感染上瘟疫，"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"이런 곳에서 마에스트로를 분간하려면 그녀가 먼저 본색을 드러내야 하리라.","JPN":"このような場所でマエストロを見分けるには、彼女から本性を現わす必要があるだろう。","ENG":"To distinguish Maestra in such a place, we must first force her to reveal her true colors.","TWN":"在這種地方要辨別出指揮家，除非是她先露出真面目。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"……그래. 괜한 기대였나. 너라면 알 수 있을 줄 알았는데.","JPN":"……そう。期待するだけ無駄だったか。あなたならわかると思ったのに。","ENG":"...I see. I guess I shouldn’t have expected it. I thought you would have been able to know whether it was her.","TWN":"……喔喔，是我太高估你嗎？我還以為你應該有辦法。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"확신하지 못하는 건가?","JPN":"確信できないのか？","ENG":"You are uncertain?","TWN":"你也不確定嗎？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"파레마라는 도시에서 한 번 마주쳤어.","JPN":"パレマという街で一度出くわしたんだ。","ENG":"I only met her once in a city called Parema.","TWN":"我曾經在波雷馬和她交手過。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"하지만 놀랍도록 인간적으로 행동하더군. 순간적으로 죽일 기회를 놓칠 만큼.","JPN":"でもビックリするほど人間的に行動していた。一瞬殺すチャンスを逃してしまったくらいに。","ENG":"But she acted surprisingly human, so I hesitated and missed my chance at killing her.","TWN":"但很意外的是，她的行為很人性化，以至於我錯失可以殺掉她的機會。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"안심해라. 놈이 본색을 드러낼 수밖에 없는 상황을 만들기로 했으니까.","JPN":"安心しろ。奴が本性を現わすしかない状況を作ることにしたから。","ENG":"Don’t worry. I have a plan that will force her to reveal herself.","TWN":"放心，我會製造出逼她露出真面目的環境。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"다만 그걸 위해서는 너도 수고해 줘야겠어.","JPN":"ただし、そのためにはあなたにも働いてもらう。","ENG":"But for it to work, I will need your help.","TWN":"只是需要你的幫忙。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MIHILE_NPC_NULL_NULL","text":{"KOREA":"허억……. 헉……. 더 쫓아오진 않는 건가?","JPN":"はあ……はあっ……もう追ってこないのか？","ENG":"*Pant* *Pant* Are they done chasing me?","TWN":"呼呼……呼呼……沒有追上來吧？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MIHILE_NPC_NULL_NULL","text":{"KOREA":"대체 누구지? 그림자들이 낌새를 알아챘나? 아니면…….","JPN":"一体誰なんだ？　シャドウたちに気取られたのか？　それとも……","ENG":"Who the hell is it? Did the Shadows notice? Or...","TWN":"到底是誰？被暗影發現了嗎？還是……？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MIHILE_NPC_NULL_NULL","text":{"KOREA":"크헉?!","JPN":"ぐはっ！？","ENG":"Hngh!?","TWN":"噢嗚？！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"요제프 클림트. 에크하르트 초월지식 학회의 회원이자…….","JPN":"ヨセフ・クリムト。エクハルト超越知識学会の会員であり……","ENG":"Yosef Klimt. Member of Eckhart's Society for Preternatural Research and...","TWN":"約瑟·克里姆，你是埃克哈特超越學會的會員……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"프리드웬 기관과 내통하는 이중첩자.","JPN":"プリドウェン機関と内通している二重スパイ。","ENG":"A double agent with the Prydwen Institution.","TWN":"同時與普利多溫機關勾結的雙面間諜。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"<color=#ffd34c>촉매</color>를 빼돌리려 하다니 그러면 안 되지. 여러 사람이 곤란해진다고.","JPN":"<color=#ffd34c>触媒</color>をこっそり横取りしようとするなんてダメだろう。いろんな人が困る。","ENG":"We can’t have you stealing the <color=#ffd34c>catalyst</color>. A lot of people are having a difficult time because of you.","TWN":"竟然想偷走<color=#ffd34c>催化劑</color>，這怎麼可以呢？這樣會造成許多人的困擾的。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MIHILE_NPC_NULL_NULL","text":{"KOREA":"학회장……?! 설마 그 여자가 악보를 노리고 보낸 건가?","JPN":"学会長……！？　まさかあの女が楽譜狙いで送ったのか？","ENG":"President of the Society...?! It can’t be. Did she send you for the musical score?","TWN":"是學會長……？！那女人派你來搶走樂譜的嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"오해하지 마. 우린 그저 마에스트로라는 트로피 때문에 잠시 협력하고 있을 뿐이니까.","JPN":"誤解するな。私たちはただマエストロというトロフィーのためにしばらく協力してるだけだからな。","ENG":"Please don’t misunderstand. We’re working together temporarily for the sake of the Maestra prize.","TWN":"你別誤會，我的目標是指揮家，現在和她只是暫時合作的關係。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MIHILE_NPC_NULL_NULL","text":{"KOREA":"이 건방진 계집애가……!","JPN":"この生意気な……！","ENG":"You puny little...!","TWN":"你這目中無人的丫頭……！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MIHILE_NPC_NULL_NULL","text":{"KOREA":"호수여! 이 피에 흐르는 지식으로 말미암아 나를 보호하소서!","JPN":"湖よ！　この血に流れる知識によって我を守りたまえ！","ENG":"Lake! Protect me with this flowing knowledge of blood!","TWN":"湖水！以這血液裡的知識保護我！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"……가아그셰블라가 남긴 잔재들인가.","JPN":"……ガアグシェブラの残滓か。","ENG":"...the remains of Gha’agsheblah.","TWN":"……是加瓦格舍夫拉遺留下來的碎片嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"역병을 다스릴 수 있다고 자만하지 말지니. 결국 스스로의 오만함에 잡아먹힐 터.","JPN":"疫病を操れると自慢するでない。結局自分の傲慢に飲み込まれることになるだろう。","ENG":"Do not be so foolish as to believe that you can control the plague. Your arrogance shall destroy you.","TWN":"據說因為能根治瘟疫而相當引以為傲，但最後還是被自己的驕傲而吞噬。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MIHILE_NPC_NULL_NULL","text":{"KOREA":"모, 모르스라고? 고고학부장이 분명 종적을 감췄다고 했는데……?","JPN":"モ、モールスだと？　考古学部長は確か姿を消したって……","ENG":"M-Mors? The Dean of Archeology said that she had disappeared...?","TWN":"你…你叫 莫爾斯？考古學教授明明說已經銷聲匿跡……？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MIHILE_NPC_NULL_NULL","text":{"KOREA":"아니, 상관없지! 그래 봐야 소문으로 부풀려진 괴물에 불과해!","JPN":"いや、どうでもいい！　しょせん噂話ででっち上げられた化け物に過ぎない！","ENG":"No, it doesn’t matter! The stories of that monster are no more than unsubstantiated rumors!","TWN":"無所謂啦！反正我看也不過就是傳言過度誇大不實吧！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MIHILE_NPC_NULL_NULL","text":{"KOREA":"호수여, 이 몸의 피와 살을 그대에게──","JPN":"湖よ、この身の血と肉をそなたに――","ENG":"Lake, take the blood and flesh of this body──","TWN":"湖水，我用我的血和肉向你──"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MIHILE_NPC_NULL_NULL","text":{"KOREA":"카학……! 컥……!","JPN":"ぐはっ……！　かは……！","ENG":"Ack…! Ack...!","TWN":"唔……！呃……！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"역병으로 영혼을 더럽히려 하는가. 그렇다면 그대가 맞이해야 할 것은 안식뿐이다.","JPN":"疫病で魂をけがそうとするのか。それならそなたが迎えるべきは安息のみであろう。","ENG":"Are you trying to defile your soul with the plague? Then truly, the only thing left for you is to face eternal rest.","TWN":"你是想藉由瘟疫汙染靈魂嗎？那你需要的是安息。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"기다려라, 모르스.","JPN":"待て、モールス。","ENG":"Wait a moment, Mors.","TWN":"先等一下，莫爾斯。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"……어찌하여 가로막는 것인가. 몽타뉴.","JPN":"……なぜ止めるのだ。モンターニュ。","ENG":"...Why do you stand in my way, Montagne?","TWN":"……蒙塔妮，你為何要攔我？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"만약을 위한 보험 때문이지.","JPN":"万が一のためだ。","ENG":"In case we need insurance.","TWN":"就當作是買個保險。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"저 남자는 이미 네 침식파에 노출됐어. 손을 더럽히지 않아도 저대로 두면 침식체로 변할 거다.","JPN":"あの男はすでにあなたの侵食波に晒された。手を汚さなくても、あのまま放っておいたら侵食体になるはずだ。","ENG":"This man has already been exposed to your Corrupted ray. Even if you do nothing and leave him as he is, he will eventually change into a Corrupted Object.","TWN":"他已經暴露在你的侵蝕波裡，不需要弄髒你的手，他也會自己變成侵蝕體。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"아. 이럴까 봐 인간들을 끼고 싸우지 않았던 건가. 덩치에 비해 속은 나약하군.","JPN":"ああ。こうなると思って他の人間と一緒に戦わなかったのか。体のわりに心は軟弱なんだな。","ENG":"Ah. So that’s why you didn’t fight with humans on your side. Your body is large but your heart is soft.","TWN":"你是因為怕會這樣才都單打獨鬥的嗎？你雖然塊頭大，裡面卻很脆弱呢。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"저 자가 말했던 악보, 가아그셰블라의 추종자들이 노릴 정도라면 예사 물건은 아닐 터.","JPN":"あの者が言っていた楽譜、ガアグシェブラの取り巻きが狙うくらいなら、普通の物ではないだろう。","ENG":"The music score he mentioned. If the Followers of Gha’agsheblah wanted it, it’s no ordinary score.","TWN":"若加瓦格舍夫拉的追隨者，也覬覦他剛說的樂譜，就表示那個東西肯定不尋常。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"회수하여 사람의 손이 닿지 않을 곳에 봉인함이 마땅하다.","JPN":"回収し、人の手が届かぬところに封印すべきだ。","ENG":"It should be recovered and sealed beyond human reach.","TWN":"應該要回收後，放到人找不到的地方封印起來才對。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"아까운 소리 하지 마. 그거야말로 우리가 저 남자를 찾아 온 이유니까.","JPN":"もったいないこと言うな。それこそ私たちがあの男を訪ねた理由なのだから。","ENG":"That goes without saying. That’s why we’re looking for him.","TWN":"這樣多可惜，那不就是我們找他找到這來的原因嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_NPC","text":{"KOREA":"여기서부터 시작되는 거야. 모르스.","JPN":"ここから始まるんだ。モールス。","ENG":"It starts here, Mors.","TWN":"現在才要正式開始呢，莫爾斯。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};